#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dirent.h>
#include <sys/stat.h>
#include <unistd.h>
#include <time.h>

#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_COMMITS 100
#define MAX_CONTENT 1024

typedef struct {
    char filename[MAX_FILENAME];
    char content[MAX_CONTENT];
} File;

typedef struct {
    int id;
    char message[256];
    File files[MAX_FILES];
    int file_count;
    time_t timestamp;
} Commit;

Commit commits[MAX_COMMITS];
int commit_count = 0;

void init() {
    mkdir(".minigit", 0755);
    FILE *index = fopen(".minigit/index", "w");
    fclose(index);
    FILE *head = fopen(".minigit/HEAD", "w");
    fprintf(head, "0\n");
    fclose(head);
    commit_count = 0;
}

int get_head() {
    FILE *head = fopen(".minigit/HEAD", "r");
    if (!head) return 0;
    int head_id;
    fscanf(head, "%d", &head_id);
    fclose(head);
    return head_id;
}

void set_head(int id) {
    FILE *head = fopen(".minigit/HEAD", "w");
    fprintf(head, "%d\n", id);
    fclose(head);
}

void add(const char *filename) {
    FILE *index = fopen(".minigit/index", "a");
    fprintf(index, "%s\n", filename);
    fclose(index);
}

void commit(const char *message) {
    int head = get_head();
    int new_id = head + 1;

    Commit *c = &commits[commit_count++];
    c->id = new_id;
    strcpy(c->message, message);
    c->timestamp = time(NULL);
    c->file_count = 0;

    FILE *index = fopen(".minigit/index", "r");
    char filename[MAX_FILENAME];
    while (fscanf(index, "%s", filename) == 1) {
        strcpy(c->files[c->file_count].filename, filename);
        FILE *f = fopen(filename, "r");
        if (f) {
            fread(c->files[c->file_count].content, 1, MAX_CONTENT, f);
            fclose(f);
        }
        c->file_count++;
    }
    fclose(index);

    char commit_path[256];
    sprintf(commit_path, ".minigit/commit_%d", new_id);
    FILE *commit_file = fopen(commit_path, "w");
    fprintf(commit_file, "%d\n%s\n%ld\n%d\n", new_id, message, c->timestamp, c->file_count);
    for (int i = 0; i < c->file_count; i++) {
        fprintf(commit_file, "%s\n%s\n", c->files[i].filename, c->files[i].content);
    }
    fclose(commit_file);

    set_head(new_id);

    index = fopen(".minigit/index", "w");
    fclose(index);
}

void checkout(int commit_id) {
    char commit_path[256];
    sprintf(commit_path, ".minigit/commit_%d", commit_id);
    FILE *commit_file = fopen(commit_path, "r");
    if (!commit_file) {
        printf("Commit %d not found\n", commit_id);
        return;
    }

    int id, file_count;
    char message[256], timestamp[256];
    fscanf(commit_file, "%d\n%[^\n]\n%[^\n]\n%d\n", &id, message, timestamp, &file_count);

    for (int i = 0; i < file_count; i++) {
        char filename[MAX_FILENAME], content[MAX_CONTENT];
        fscanf(commit_file, "%[^\n]\n%[^\n]\n", filename, content);

        FILE *f = fopen(filename, "w");
        fprintf(f, "%s\n", content);
        fclose(f);
    }
    fclose(commit_file);

    set_head(commit_id);
}

void reset(int commit_id) {
    char commit_path[256];
    sprintf(commit_path, ".minigit/commit_%d", commit_id);
    FILE *commit_file = fopen(commit_path, "r");
    if (!commit_file) {
        printf("Commit %d not found\n", commit_id);
        return;
    }
    fclose(commit_file);

    for (int i = commit_id + 1; i <= commit_count; i++) {
        sprintf(commit_path, ".minigit/commit_%d", i);
        remove(commit_path);
    }

    commit_count = commit_id;
    set_head(commit_id);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: minigit <command> [args]\n");
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            printf("Usage: minigit add <file>\n");
            return 1;
        }
        add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) {
            printf("Usage: minigit commit <message>\n");
            return 1;
        }
        commit(argv[2]);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            printf("Usage: minigit checkout <commit_id>\n");
            return 1;
        }
        checkout(atoi(argv[2]));
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            printf("Usage: minigit reset <commit_id>\n");
            return 1;
        }
        reset(atoi(argv[2]));
    } else {
        printf("Unknown command: %s\n", argv[1]);
        return 1;
    }

    return 0;
}
